/* Forward pass: evaluate ROM */
static void rom_evaluate(const double* inputs, double* outputs) {
  double a[32], b[32];
  double normed[N_INPUTS];

  /* Normalize inputs */
  for (int i = 0; i < N_INPUTS; i++)
    normed[i] = (inputs[i] - in_mean[i]) / in_std[i];

  /* Layer 0: 1 → 32 (tanh) */
  for (int i = 0; i < 32; i++) {
    double z = b0[i];
    for (int j = 0; j < 1; j++) z += W0[i][j] * normed[j];
    a[i] = tanh(z);
  }

  /* Layer 1: 32 → 16 (tanh) */
  for (int i = 0; i < 16; i++) {
    double z = b1[i];
    for (int j = 0; j < 32; j++) z += W1[i][j] * a[j];
    b[i] = tanh(z);
  }

  /* Layer 2: 16 → 2 (linear output) */
  for (int i = 0; i < 2; i++) {
    double z = b2[i];
    for (int j = 0; j < 16; j++) z += W2[i][j] * b[j];
    b[i] = z;
  }

  /* Denormalize outputs */
  for (int i = 0; i < N_OUTPUTS; i++)
    outputs[i] = a[i] * out_std[i] + out_mean[i];
}

